class Solution {
public:
    vector<int> sequentialDigits(int low, int high) {
        vector<int> res;
        for (int len = 1; len <= to_string(high).size(); len++) {
            for (int start = 1; start <= 9 - len + 1; start++) {
                long long num = 0;
                for (int i = 0; i < len; i++) {
                    num = num * 10 + start + i;
                }
                if (num >= low && num <= high) {
                    res.push_back(num);
                }
            }
        }
        return res;
    }
};
